class Solution:
    def lexicalOrder(self, n):
        """
        :type n: int
        :rtype: List[int]
        """
        result = []
        current = 1

        for _ in range(n):
            result.append(current)

            # Try to go deeper (multiply by 10)
            if current * 10 <= n:
                current *= 10
            else:
                # Go to next number at same or higher level
                while current % 10 == 9 or current + 1 > n:
                    current //= 10
                current += 1

        return result
